import { app, Menu, Tray, nativeImage } from 'electron';
import path from 'path';
let tray = null;
let mainWindow = null;
let isQuitting = false;
export const setMainWindow = (window) => {
    mainWindow = window;
};
export const getIsQuitting = () => isQuitting;
export const setIsQuitting = (value) => {
    isQuitting = value;
};
const createTrayIcon = () => {
    // Use different icon paths based on platform
    let iconPath;
    if (process.platform === 'darwin') {
        // macOS uses 16x16 or 18x18 template icons
        iconPath = path.join(process.resourcesPath, 'tray-iconTemplate.png');
    }
    else if (process.platform === 'win32') {
        // Windows uses ICO or PNG
        iconPath = path.join(process.resourcesPath, 'tray-icon.png');
    }
    else {
        // Linux uses PNG
        iconPath = path.join(process.resourcesPath, 'tray-icon.png');
    }
    try {
        const icon = nativeImage.createFromPath(iconPath);
        // On macOS, mark as template image for dark mode support
        if (process.platform === 'darwin') {
            icon.setTemplateImage(true);
        }
        return icon;
    }
    catch {
        // Fallback: create a simple colored square icon programmatically
        // 16x16 transparent PNG as base64 (simple blue square)
        const fallbackIcon = nativeImage.createFromBuffer(Buffer.from('iVBORw0KGgoAAAANSUhEUgAAABAAAAAQCAYAAAAf8/9hAAAABHNCSVQICAgIfAhkiAAAAAlwSFlzAAAAdgAAAHYBTnsmCAAAABl0RVh0U29mdHdhcmUAd3d3Lmlua3NjYXBlLm9yZ5vuPBoAAABVSURBVDiNY2AYBaNg2ALG/xjogmE0Y//DwPgfDNg0wKYZRjOQGohqAIpPxjCYJqhmGI0t0Dg0w2hsoEajNUNpRlMzU2gG08ygZ6bRaKbVzAQAxBEU/X8q+UAAAAAASUVORK5CYII=', 'base64'));
        return fallbackIcon;
    }
};
const showWindow = () => {
    if (mainWindow) {
        if (mainWindow.isMinimized()) {
            mainWindow.restore();
        }
        mainWindow.show();
        mainWindow.focus();
    }
};
let checkForUpdatesFn = null;
export const setCheckForUpdatesFn = (fn) => {
    checkForUpdatesFn = fn;
};
const createContextMenu = () => {
    const template = [
        {
            label: 'Open Dashboard',
            click: showWindow
        },
        { type: 'separator' }
    ];
    // Add check for updates if available
    if (checkForUpdatesFn) {
        template.push({
            label: 'Check for Updates',
            click: checkForUpdatesFn
        });
        template.push({ type: 'separator' });
    }
    template.push({
        label: 'Quit',
        click: () => {
            isQuitting = true;
            app.quit();
        }
    });
    return Menu.buildFromTemplate(template);
};
export const createTray = () => {
    if (tray) {
        return tray;
    }
    const icon = createTrayIcon();
    tray = new Tray(icon);
    tray.setToolTip('AOP Desktop');
    tray.setContextMenu(createContextMenu());
    // Click behavior varies by platform
    tray.on('click', () => {
        if (process.platform === 'darwin') {
            // macOS: left click shows context menu
            tray?.popUpContextMenu();
        }
        else {
            // Windows/Linux: left click toggles window
            if (mainWindow?.isVisible()) {
                mainWindow.hide();
            }
            else {
                showWindow();
            }
        }
    });
    tray.on('double-click', showWindow);
    return tray;
};
export const destroyTray = () => {
    if (tray) {
        tray.destroy();
        tray = null;
    }
};
export const updateTrayTooltip = (tooltip) => {
    if (tray) {
        tray.setToolTip(tooltip);
    }
};
